SELECT COUNT(*)
FROM NMCP_CONT_RATE_ADDITION
WHERE 1=1
AND CONT_KIND = #{contKind}

    AND CD_GROUP_ID1 = #{cdGroupId1}


    AND CD_GROUP_ID2 = #{cdGroupId2}


    AND USE_YN = #{useYn}



        AND UPPER(CONT_TITLE) LIKE '%'|| UPPER(#{searchText}) ||'%'


        AND UPPER(FNHTMLTOTEXT(CONT_CONTENT)) LIKE '%'|| UPPER(#{searchText}) ||'%'

SELECT
            COUNT(*)
FROM   NMCP_CONT_RATE_ADDITION
WHERE   1=1
AND CONT_KIND = #{contKind}
    AND USE_YN = 'Y'

    AND CD_GROUP_ID1 = #{cdGroupId1}


    AND CD_GROUP_ID2 = #{cdGroupId2}


    AND USE_YN = #{useYn}

SELECT CONT_SEQ, CONT_KIND, CD_GROUP_ID1, CD_GROUP_ID2, USE_YN, CONT_TITLE, CONT_TEXT, CONT_CONTENT, PAY, PAYVAT, PAY_YN, CRET_ID, CRET_DT, AMD_ID, AMD_DT, CONT_IMG FROM NMCP_CONT_RATE_ADDITION WHERE 1=1 AND CONT_KIND = #{contKind} AND USE_YN = 'Y'
AND CD_GROUP_ID1 = #{cdGroupId1}
AND CD_GROUP_ID2 = #{cdGroupId2}
AND USE_YN = #{useYn}
ORDER BY CONT_SEQ DESC

SELECT RNUM, CONT_SEQ, CONT_KIND, CD_GROUP_ID1, CD_GROUP_ID2, USE_YN, CONT_TITLE, CONT_TEXT, CONT_CONTENT, PAY, PAYVAT, PAY_YN, CRET_ID, CRET_DT, AMD_ID, AMD_DT FROM ( SELECT ROW_NUMBER() OVER (ORDER BY TO_NUMBER(CONT_SEQ) DESC) AS RNUM, CONT_SEQ, CONT_KIND, CD_GROUP_ID1, CD_GROUP_ID2, USE_YN, CONT_TITLE, CONT_TEXT, CONT_CONTENT, PAY, PAYVAT, PAY_YN, CRET_ID, CRET_DT, AMD_ID, AMD_DT FROM NMCP_CONT_RATE_ADDITION WHERE 1=1 AND CONT_KIND = #{contKind}
AND CD_GROUP_ID1 = #{cdGroupId1}
AND CD_GROUP_ID2 = #{cdGroupId2}
AND USE_YN = #{useYn}
AND UPPER(CONT_TITLE) LIKE '%'|| UPPER(#{searchText}) ||'%'
AND UPPER(FNHTMLTOTEXT(CONT_CONTENT)) LIKE '%'|| UPPER(#{searchText}) ||'%'
) WHERE RNUM > (#{pagingStartNo}-1) * #{pagingSize} AND RNUM <= #{pagingEndNo} * #{pagingStartNo}

SELECT /*ContMapper.selectView */ CONT_KIND , CD_GROUP_ID1 , CD_GROUP_ID2 , USE_YN , CONT_TITLE , CONT_TEXT , CONT_CONTENT , PAY , PAYVAT , PAY_YN , CRET_ID , CRET_DT , AMD_ID , AMD_DT , CONT_SEQ , SOC_CODE , CONT_IMG , CONT_MOBILE_CONTENT FROM NMCP_CONT_RATE_ADDITION WHERE 1=1
AND SOC_CODE = #{socCode}
AND CONT_SEQ = #{contSeq}

mapper.update:
UPDATE NMCP_CONT_RATE_ADDITION SET CD_GROUP_ID1 = #{cdGroupId1}, CD_GROUP_ID2 = #{cdGroupId2}, USE_YN = #{useYn}, CONT_TITLE = #{contTitle}, CONT_TEXT = #{contText}, CONT_CONTENT = #{contContent}, PAY = #{pay}, PAYVAT = #{payvat}, PAY_YN = #{payYn}, AMD_ID = #{amdId}, AMD_DT = SYSDATE, SOC_CODE = UPPER(#{socCode}),
CONT_IMG = #{contImg},
CONT_MOBILE_CONTENT = #{contMobileContent} WHERE CONT_SEQ = #{contSeq}

mapper.select:
SELECT  COUNT(CONT_SEQ)
FROM    NMCP_CONT_RATE_ADDITION
WHERE   1=1
    AND USE_YN = 'Y'

    AND	CONT_KIND = #{contKind}


    AND CD_GROUP_ID1 = #{cdGroupId1}


    AND CD_GROUP_ID2 = #{cdGroupId2}



        AND UPPER(CONT_TITLE) LIKE '%'|| UPPER(#{searchText}) ||'%'


        AND UPPER(FNHTMLTOTEXT(CONT_CONTENT)) LIKE '%'|| UPPER(#{searchText}) ||'%'

SELECT RNUM , RNUM_ORDER , CONT_SEQ , CD_GROUP_ID1 , CD_GROUP_ID2 , USE_YN , CONT_TITLE , CONT_TEXT , CONT_MOBILE_CONTENT , PAY , PAYVAT , PAY_YN , CRET_ID , CRET_DT , AMD_ID , AMD_DT , CONT_IMG FROM ( SELECT ROW_NUMBER () OVER (ORDER BY CONT_SEQ DESC) AS RNUM_ORDER ,ROW_NUMBER () OVER (ORDER BY CONT_SEQ ASC) AS RNUM , CONT_SEQ , CD_GROUP_ID1 , CD_GROUP_ID2 , USE_YN , CONT_TITLE , CONT_TEXT , CONT_MOBILE_CONTENT , PAY , PAYVAT , PAY_YN , CRET_ID , CRET_DT , AMD_ID , AMD_DT , CONT_IMG FROM NMCP_CONT_RATE_ADDITION WHERE 1=1 AND USE_YN = 'Y'
AND CONT_KIND = #{contKind}
AND CD_GROUP_ID1 = #{cdGroupId1}
AND CD_GROUP_ID2 = #{cdGroupId2}
AND USE_YN = #{useYn}
AND UPPER(CONT_TITLE) LIKE '%'|| UPPER(#{searchText}) ||'%'
AND UPPER(FNHTMLTOTEXT(CONT_CONTENT)) LIKE '%'|| UPPER(#{searchText}) ||'%'
) ORDER BY RNUM DESC

SELECT NATION_RATE_KEY, NATION_NAME_EN, NATION_NAME_KR, RATE_SECOND, RATE_MINUTE, NATION_CODE, SDATE
FROM MCP_NATION_RATE


        AND  NATION_NAME_KR  = #{schVal}


        AND NATION_RATE_KEY = #{selVal}

