UPDATE NMCP_WIRE_PROD_DTL SET WIRE_PROD_CD = #{wireProdCd}, WIRE_PROD_CORP = #{wireProdCorp}, WIRE_PROD_NAME = #{wireProdName}, WIRE_PROD_STICKER = #{wireProdSticker}, WIRE_PROD_AMT = #{wireProdAmt}, WIRE_PROD_AMT_DESC = #{wireProdAmtDesc}, WIRE_PROD_AMT_TEXT = #{wireProdAmtText}, WIRE_PROD_AMT_TYPE = #{wireProdAmtType}, WIRE_PROD_SHOW_YN = #{wireProdShowYn}, WIRE_PROD_RECOM_YN = #{wireProdRecomYn},
WIRE_PROD_IMG = #{wireProdImg},
WIRE_PROD_IMG_DESC = #{wireProdImgDesc}, WIRE_PROD_TEXT = #{wireProdText}, WIRE_PROD_PC_SBST = #{wireProdPcSbst}, WIRE_PROD_MOBILE_SBST = #{wireProdMobileSbst}, WIRE_PROD_REG_ID = #{wireProdRegId}, WIRE_PROD_REG_DT = SYSDATE, WIRE_PROD_CHANNEL= #{wireProdChannel}, WIRE_PROD_SPEED = #{wireProdSpeed}, WIRE_PROD_FREEBIES = #{wireProdFreebies} WHERE WIRE_PROD_DTL_SEQ = #{wireProdDtlSeq}

mapper.select:
SELECT /*ContMapper.countWireCounselList 유선상담관리 리스트 갯수 */ COUNT(T1.COUNSEL_SEQ) FROM NMCP_WIRE_COUNSEL T1, NMCP_WIRE_PROD_DTL T2 WHERE 1=1 AND T1.WIRE_PROD_DTL_SEQ = T2.WIRE_PROD_DTL_SEQ(+)
AND T1.DONE_DT BETWEEN TO_DATE(#{startDate},'YYYY.MM.DD HH24') AND TO_DATE(#{endDate},'YYYY.MM.DD HH24')+1
AND T1.COUNSEL_REG_DT BETWEEN TO_DATE(#{startDate},'YYYY.MM.DD HH24') AND TO_DATE(#{endDate},'YYYY.MM.DD HH24')+1
AND WIRE_PROD_CORP = #{wireProdCorp}
AND WIRE_PROD_CD = #{wireProdCd}
AND COUNSEL_STATUS = #{counselStatus}
AND UPPER()COUNSEL_NM) LIKE '%'|| UPPER(#{searchTxt}) ||'%'
AND COUNSEL_CTN LIKE '%'|| #{searchTxt} ||'%'

SELECT /*ContMapper.getWireCounselList 유선상담관리 리스트 */ COUNSEL_SEQ , T1.WIRE_PROD_DTL_SEQ , COUNSEL_NM , COUNSEL_CTN , COUNSEL_MEMO , COUNSEL_REG_DT , COUNSEL_STATUS , RVISN_DT , DONE_DT , PRO_STATUS , WIRE_PROD_CD --구분코드 중분류.. , WIRE_PROD_CORP -- 사업자. , WIRE_PROD_NAME -- 소분류 제품명 FROM NMCP_WIRE_COUNSEL T1, NMCP_WIRE_PROD_DTL T2 WHERE 1=1 AND T1.WIRE_PROD_DTL_SEQ = T2.WIRE_PROD_DTL_SEQ(+)
AND T1.DONE_DT BETWEEN TO_DATE(#{startDate},'YYYY.MM.DD HH24') AND TO_DATE(#{endDate},'YYYY.MM.DD HH24')+1
AND T1.COUNSEL_REG_DT BETWEEN TO_DATE(#{startDate},'YYYY.MM.DD HH24') AND TO_DATE(#{endDate},'YYYY.MM.DD HH24')+1
AND WIRE_PROD_CORP = #{wireProdCorp}
AND WIRE_PROD_CD = #{wireProdCd}
AND COUNSEL_STATUS = #{counselStatus}
AND COUNSEL_NM LIKE '%'|| UPPER(#{searchTxt}) ||'%'
AND COUNSEL_CTN LIKE '%'|| UPPER(#{searchTxt}) ||'%'
ORDER BY COUNSEL_REG_DT DESC

mapper.insert:

        SELECT NVL((MAX(HISTORY_IDX)+1),1) AS historyIdx
        FROM NMCP_WIRE_COUNSEL_HISTORY
        WHERE COUNSEL_SEQ = #{counselSeq}

INSERT INTO NMCP_WIRE_COUNSEL_HISTORY (
      COUNSEL_SEQ              --상담번호
    , HISTORY_IDX              --상담일련번호
    , ADMIN_ID                 --등록자아이디
    , ADMIN_NM                 --등록자명
    , COUNSEL_MEMO             --상담 내용
    , REG_DT                   --등록일
) VALUES (
      #{counselSeq}
    , #{historyIdx}
    , #{adminId}
    , #{adminNm}
    , #{counselMemo}
     , SYSDATE
)
